/**
 * @summary Get AI-powered top 3 match suggestions nearby
 */
export const getGetMatchSuggestionsUrl = (
  params: GetMatchSuggestionsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/matches/suggestions?${stringifiedParams}`
    : `/api/matches/suggestions`;
};

export const getMatchSuggestions = async (
  params: GetMatchSuggestionsParams,
  options?: RequestInit,
): Promise<MatchSuggestion[]> => {
  return customFetch<MatchSuggestion[]>(getGetMatchSuggestionsUrl(params), {
    ...options,
    method: "GET",
  });
};

